    vol_spike = volumes[-1] / vol_avg if vol_avg > 0 else 1

    # Scoring
    long_score = 0
    short_score = 0

    if trend == "BULLISH":
        long_score += 25
    elif trend == "BEARISH":
        short_score += 25

    if roc_5 > 0.004:
