        confidence = short_score / 100

    if direction and confidence >= 0.55:
        # Calculate SL/TP
        atr = (max(highs[-10:]) - min(lows[-10:])) / 10

        if direction == "Buy":
            recent_low = min(lows[-5])
            sl = recent_low - atr * 0.5
            risk = current - sl
            tp = current + risk * 2
        else:
            recent_high = max(highs[-5])
            sl = recent_high + atr * 0.5
            risk = sl - current
            tp = current - risk * 2

        rr = abs(tp - current) / abs(current - sl) if abs(current - sl) > 0 else 0

        if rr >= 1.5:
            trade_signals.append({
                "symbol": symbol,
                "direction": direction,
                "confidence": confidence,
                "entry": current,
                "sl": round(sl, 4),
                "tp": round(tp, 4),
                "rr": round(rr, 2),
                "leverage": sym_data["maxLeverage"]
            })

print(f"🎯 Found {len(trade_signals)} setups")

# Sort by confidence
trade_signals.sort(key=lambda x: x["confidence"], reverse=True)

# Show top setups
